<template><div class="page-container"><div class="page-card"><div class="header"><div><h2>Offer 管理</h2><p>向通过面试的学生发送 Offer，并跟踪确认状态。</p></div><el-button type="primary" @click="open()">发送Offer</el-button></div><el-divider/><el-table :data="list" stripe v-loading="loading"><el-table-column prop="position" label="岗位" min-width="160"/><el-table-column prop="salary" label="薪资" width="120"/><el-table-column prop="workCity" label="城市" width="100"/><el-table-column prop="reportTime" label="报到时间" width="140"/><el-table-column label="状态" width="110"><template #default="{row}"><el-tag :type="type(row.offerStatus)">{{['待确认','已接受','已拒绝','已撤回'][row.offerStatus]}}</el-tag></template></el-table-column><el-table-column label="操作" width="140"><template #default="{row}"><el-button v-if="row.offerStatus===0" text type="danger" @click="revoke(row)">撤回</el-button></template></el-table-column></el-table><div class="pagination-wrap"><el-pagination v-model:current-page="query.pageNum" :total="total" background layout="total,prev,pager,next" @current-change="load"/></div></div><el-dialog v-model="dialog" title="发送 Offer" width="620px"><el-form :model="form" label-width="100px"><el-form-item label="投递ID"><el-input-number v-model="form.applyId" :min="1"/></el-form-item><el-form-item label="学生ID"><el-input-number v-model="form.studentId" :min="1"/></el-form-item><el-form-item label="岗位ID"><el-input-number v-model="form.jobId" :min="1"/></el-form-item><el-form-item label="岗位名称"><el-input v-model="form.position"/></el-form-item><el-form-item label="薪资"><el-input v-model="form.salary" placeholder="如 15K*14薪"/></el-form-item><el-form-item label="工作城市"><el-input v-model="form.workCity"/></el-form-item><el-form-item label="报到时间"><el-input v-model="form.reportTime"/></el-form-item><el-form-item label="Offer内容"><el-input v-model="form.content" type="textarea" :rows="4"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="send">发送</el-button></template></el-dialog></div></template>
<script setup>import{reactive,ref,onMounted}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{enterpriseApi}from'@/api';const query=reactive({pageNum:1,pageSize:10});const list=ref([]),total=ref(0),loading=ref(false),dialog=ref(false);const form=reactive({});const type=s=>s===1?'success':s===2?'danger':s===3?'info':'warning';const load=async()=>{loading.value=true;try{const r=await enterpriseApi.offerList(query);list.value=r.data.records;total.value=Number(r.data.total)}finally{loading.value=false}};const open=()=>{Object.keys(form).forEach(k=>delete form[k]);Object.assign(form,{offerStatus:0});dialog.value=true};const send=async()=>{await enterpriseApi.sendOffer(form);ElMessage.success('Offer已发送');dialog.value=false;load()};const revoke=row=>ElMessageBox.confirm('确定撤回该 Offer？').then(async()=>{await enterpriseApi.revokeOffer(row.id);ElMessage.success('已撤回');load()});onMounted(load)</script>
<style scoped>.header{display:flex;justify-content:space-between;align-items:center}.header h2{margin-bottom:6px}.header p{color:#909399}</style>